 1	import React, { FC } from 'react';
 2	
 3	import LinuxLabel from '@kubevirt-utils/components/Labels/LinuxLabel';
 4	import SearchItem from '@kubevirt-utils/components/SearchItem/SearchItem';
 5	import SidebarEditor from '@kubevirt-utils/components/SidebarEditor/SidebarEditor';
 6	import { useKubevirtTranslation } from '@kubevirt-utils/hooks/useKubevirtTranslation';
 7	import { PATHS_TO_HIGHLIGHT } from '@kubevirt-utils/resources/vm/utils/constants';
 8	import {
 9	  DescriptionList,
10	  Grid,
11	  GridItem,
12	  PageSection,
13	  PageSectionVariants,
14	  Stack,
15	  Title,
16	} from '@patternfly/react-core';
17	
18	import { onSubmitYAML } from '../details/utils/utils';
19	import { ConfigurationInnerTabProps } from '../utils/types';
20	
21	import SSHTabAuthorizedSSHKey from './components/SSHTabAuthorizedSSHKey';
22	import SSHTabSSHAccess from './components/SSHTabSSHAccess';
23	
24	const SSHTab: FC<ConfigurationInnerTabProps> = ({ vm }) => {
25	  const { t } = useKubevirtTranslation();
26	
27	  return (
28	    <SidebarEditor
29	      onResourceUpdate={onSubmitYAML}
30	      pathsToHighlight={PATHS_TO_HIGHLIGHT.SCRIPTS_TAB}
31	      resource={vm}
32	    >
33	      <PageSection variant={PageSectionVariants.light}>
34	        <Title headingLevel="h2">
35	          <SearchItem id="ssh">
36	            {t('SSH settings')} <LinuxLabel />
37	          </SearchItem>
38	        </Title>
39	        <Grid span={6}>
40	          <GridItem>
41	            <Stack hasGutter>
42	              <DescriptionList className="pf-v6-c-description-list">
43	                <SSHTabSSHAccess vm={vm} />
44	                <SSHTabAuthorizedSSHKey vm={vm} />
45	              </DescriptionList>
46	            </Stack>
47	          </GridItem>
48	        </Grid>
49	      </PageSection>
50	    </SidebarEditor>
51	  );
52	};
53	
54	export default SSHTab;

